"""PortStore — 포트 기반 데이터 저장과 와이어링."""

from __future__ import annotations

import logging
from typing import Any

from mantis.models.node import NodeInfo, EdgeInfo
from mantis.runtime.stream_manager import StreamManager

logger = logging.getLogger(__name__)


class PortStore:
    """노드 간 데이터를 포트 단위로 저장하고 연결한다."""

    def __init__(self, stream_manager: StreamManager, edges: list[EdgeInfo]):
        self._outputs: dict[str, dict[str, Any]] = {}
        self._stream = stream_manager
        self._edges = edges

    def wire(self, node: NodeInfo) -> dict[str, Any]:
        """엣지를 따라 upstream 출력을 현재 노드 입력으로 연결."""
        kwargs: dict[str, Any] = {}

        # 이 노드로 들어오는 엣지 찾기
        incoming = [e for e in self._edges if e.target_node == node.id]

        for edge in incoming:
            source_outputs = self._outputs.get(edge.source_node, {})
            value = source_outputs.get(edge.source_port)

            if value is None:
                continue

            # Generator 팬아웃: 같은 source port에서 여러 엣지가 나가면 복제
            if self._stream.is_generator(value):
                consumer_count = sum(
                    1 for e in self._edges
                    if e.source_node == edge.source_node and e.source_port == edge.source_port
                )
                if consumer_count > 1:
                    copies = self._stream.fan_out(value, consumer_count)
                    # 첫 번째를 현재 사용, 나머지를 원래 위치에 다시 저장
                    value = copies[0]
                    # BufferedFactory로 교체 (이후 소비자가 새 generator를 받도록)
                    from mantis.runtime.stream_manager import BufferedFactory
                    if not isinstance(source_outputs.get(edge.source_port), BufferedFactory):
                        factory = self._stream.buffer(value) if self._stream.is_generator(value) else None
                        if factory:
                            source_outputs[edge.source_port] = factory
                            value = factory.create_generator()

            # 멀티 포트 (여러 엣지 → 같은 입력)
            target_port = edge.target_port
            if target_port in kwargs:
                existing = kwargs[target_port]
                if isinstance(existing, list):
                    existing.append(value)
                else:
                    kwargs[target_port] = [existing, value]
            else:
                kwargs[target_port] = value

        # 파라미터 머지 (엣지가 없는 입력은 파라미터에서)
        for key, val in node.parameters.items():
            kwargs.setdefault(key, val)

        return kwargs

    def store(self, node: NodeInfo, result: dict[str, Any]) -> None:
        """노드 실행 결과를 포트별로 저장."""
        self._outputs[node.id] = result

    def get(self, node_id: str) -> dict[str, Any]:
        return self._outputs.get(node_id, {})

    def collect_endnodes(self, endnode_ids: list[str]) -> dict[str, Any]:
        """모든 endnode 결과를 수집."""
        if len(endnode_ids) == 1:
            outputs = self._outputs.get(endnode_ids[0], {})
            return outputs.get("result", outputs)
        results = {}
        for nid in endnode_ids:
            outputs = self._outputs.get(nid, {})
            results[nid] = outputs.get("result", outputs)
        return results
